/**
 * Timeline configuration for standup comedy video generation.
 * Generated by scripts/generate_standup_timeline.py from transcript.json.
 */

/** Text animation effect type */
export type TextAnimation =
  | "fadeIn"        // 淡入
  | "springIn"      // 弹性弹入（从下方）
  | "scaleUp"       // 从小放大
  | "scaleDown"     // 从大缩小
  | "typewriter"    // 打字机
  | "bounce"        // 弹跳
  | "shake"         // 抖动（适合笑点/吐槽）
  | "slam"          // 砸入（文字从大号急速缩到正常）
  | "wave"          // 波浪形逐字出现
  | "glitch"        // 故障闪烁效果
  | "rotateIn"      // 旋转进入
  | "splitReveal";  // 从中间向两边展开

/** Scene transition type */
export type TransitionType =
  | "fade"
  | "slide"
  | "wipe"
  | "none";

/** Background style */
export interface Background {
  type: "gradient" | "solid" | "radial";
  colors: string[];
  /** Optional animated gradient angle shift */
  animateAngle?: boolean;
}

/** A single scene (typically one sentence or a short phrase) */
export interface Scene {
  id: number;
  /** Start time in milliseconds (from audio) */
  startMs: number;
  /** End time in milliseconds */
  endMs: number;
  /** Text to display */
  text: string;
  /** Animation effect for this scene's text */
  animation: TextAnimation;
  /** Font size multiplier (1.0 = normal, 1.5 = emphasis, 2.0 = punchline) */
  emphasis: number;
  /** Background for this scene */
  background: Background;
  /** Text color */
  textColor: string;
  /** Optional: secondary text (e.g. translation, annotation) */
  subText?: string;
  /** Transition to next scene */
  transition: {
    type: TransitionType;
    durationMs: number;
  };
}

/** Full timeline configuration */
export interface Timeline {
  /** Frames per second */
  fps: number;
  /** Video width */
  width: number;
  /** Video height */
  height: number;
  /** Path to the audio file (relative to public/) */
  audioSrc: string;
  /** Font family for main text */
  fontFamily: string;
  /** Font family for secondary text */
  subFontFamily?: string;
  /** All scenes */
  scenes: Scene[];
  /** Show progress bar */
  showProgressBar: boolean;
  /** Progress bar color */
  progressBarColor: string;
  /** Show audio waveform */
  showWaveform: boolean;
  /** Waveform color */
  waveformColor: string;
}

/** Props passed to the root Remotion composition */
export interface StandupVideoProps {
  timeline: Timeline;
}
